// Check if current time is within business hours (9am-5pm HST)
const now = new Date();

// Hawaii Standard Time = UTC - 10 (no daylight saving ever)
const utcHours = now.getUTCHours();
const utcDay = now.getUTCDay(); // 0=Sun, 1=Mon ... 6=Sat
let hstHours = utcHours - 10;
let hstDay = utcDay;
if (hstHours < 0) {
  hstHours += 24;
  hstDay = (hstDay - 1 + 7) % 7;
}

const isWeekday = hstDay >= 1 && hstDay <= 5;
const isWithinHours = hstHours >= 9 && hstHours < 17;
const isBusinessHours = isWeekday && isWithinHours;

return [{
  json: {
    ...items[0].json,
    isBusinessHours,
    hstHours,
    hstDay
  }
}];

